# ============================================================
#  Propora Assistent - Installations-Skript (v3)
# ============================================================

$ProjectRoot = "C:\Users\domin\OneDrive\Desktop\Immo-analyzer\frontend"

Write-Host ""
Write-Host "Propora Assistent - Installation" -ForegroundColor Yellow
Write-Host "================================" -ForegroundColor Yellow
Write-Host ""

if (-not (Test-Path $ProjectRoot)) {
    Write-Host "FEHLER: Projektverzeichnis nicht gefunden: $ProjectRoot" -ForegroundColor Red
    exit 1
}
Write-Host "OK  Projekt gefunden: $ProjectRoot" -ForegroundColor Green

$ComponentDir = Join-Path $ProjectRoot "src\components\Assistent"
New-Item -ItemType Directory -Force -Path $ComponentDir | Out-Null
Write-Host "OK  Ordner erstellt: src/components/Assistent" -ForegroundColor Cyan

$ComponentB64 = ""
$ApiB64 = ""

$componentBytes = [System.Convert]::FromBase64String($ComponentB64)
[System.IO.File]::WriteAllBytes((Join-Path $ComponentDir "index.tsx"), $componentBytes)
Write-Host "OK  Komponente erstellt: src/components/Assistent/index.tsx" -ForegroundColor Green

$IsNextJs = (Test-Path (Join-Path $ProjectRoot "pages")) -or (Test-Path (Join-Path $ProjectRoot "src\pages"))
if ($IsNextJs) {
    $ApiDir = Join-Path $ProjectRoot "pages\api"
    if (Test-Path (Join-Path $ProjectRoot "src\pages")) {
        $ApiDir = Join-Path $ProjectRoot "src\pages\api"
    }
} else {
    $ApiDir = Join-Path $ProjectRoot "src\api"
}
New-Item -ItemType Directory -Force -Path $ApiDir | Out-Null

$apiBytes = [System.Convert]::FromBase64String($ApiB64)
[System.IO.File]::WriteAllBytes((Join-Path $ApiDir "assistent.ts"), $apiBytes)
Write-Host "OK  API Route erstellt in: $ApiDir" -ForegroundColor Green

$EnvFile = Join-Path $ProjectRoot ".env.local"
if (-not (Test-Path $EnvFile)) {
    "ANTHROPIC_API_KEY=sk-ant-DEINEN-KEY-HIER-EINTRAGEN" | Set-Content -Path $EnvFile -Encoding UTF8
    Write-Host "OK  .env.local erstellt - trage deinen API Key ein!" -ForegroundColor Yellow
} else {
    $envContent = Get-Content $EnvFile -Raw
    if ($envContent -notmatch "ANTHROPIC_API_KEY") {
        Add-Content -Path $EnvFile -Value "`nANTHROPIC_API_KEY=sk-ant-DEINEN-KEY-HIER-EINTRAGEN"
        Write-Host "OK  ANTHROPIC_API_KEY zu .env.local hinzugefuegt" -ForegroundColor Yellow
    } else {
        Write-Host "INFO ANTHROPIC_API_KEY bereits vorhanden" -ForegroundColor Cyan
    }
}

Write-Host ""
Write-Host "Installiere @anthropic-ai/sdk ..." -ForegroundColor Cyan
Set-Location $ProjectRoot
npm install @anthropic-ai/sdk --save
if ($LASTEXITCODE -eq 0) {
    Write-Host "OK  @anthropic-ai/sdk installiert" -ForegroundColor Green
} else {
    Write-Host "WARNUNG npm install fehlgeschlagen - manuell ausfuehren:" -ForegroundColor Yellow
    Write-Host "  cd $ProjectRoot" -ForegroundColor Gray
    Write-Host "  npm install @anthropic-ai/sdk" -ForegroundColor Gray
}

Write-Host ""
Write-Host "======================================================" -ForegroundColor Yellow
Write-Host "LETZTER SCHRITT - Einbinden in App.tsx oder main.tsx" -ForegroundColor Yellow
Write-Host "======================================================" -ForegroundColor Yellow
Write-Host ""
Write-Host "1) Import hinzufuegen:" -ForegroundColor White
Write-Host "   import PropraAssistent from './components/Assistent';" -ForegroundColor Cyan
Write-Host ""
Write-Host "2) Vor dem letzten </div> einfuegen:" -ForegroundColor White
Write-Host "   <PropraAssistent />" -ForegroundColor Cyan
Write-Host ""
Write-Host "3) API Key in .env.local eintragen!" -ForegroundColor White
Write-Host ""
Write-Host "Fertig! Viel Erfolg mit Propora." -ForegroundColor Green
Write-Host ""
